
INSERT INTO categories (category_name, category_description) VALUES 

(N'Giúp việc trông trẻ', N'Dịch vụ trông nom, chăm sóc trẻ em khi bố mẹ đi làm hoặc có việc bận'),
(N'Giúp việc chăm người già', N'Chăm sóc tận tình người cao tuổi, hỗ trợ sinh hoạt và theo dõi sức khỏe'),
(N'Giúp việc dọn dẹp nhà cửa', N'Dọn dẹp, vệ sinh toàn bộ không gian sống một cách chuyên nghiệp'),
(N'Giúp việc nấu ăn', N'Nấu ăn gia đình ngon miệng, đảm bảo dinh dưỡng và an toàn thực phẩm'),
(N'Giúp việc theo giờ', N'Dịch vụ linh hoạt theo từng giờ, phù hợp với nhu cầu ngắn hạn'),
(N'Gia sư cơ bản', N'Dạy kèm các môn học cơ bản cho trẻ em từ mầm non đến tiểu học'),

-- Từ phần các dịch vụ khác
(N'Giúp việc toàn thời gian', N'Người giúp việc làm việc toàn thời gian, ở lại hoặc đi về hàng ngày'),
(N'Giúp việc theo hợp đồng', N'Dịch vụ theo hợp đồng dài hạn với cam kết chất lượng và ưu đãi'),
(N'Tài xế gia đình', N'Dịch vụ lái xe đưa đón gia đình, đi chợ, đi làm, đưa con đi học'),
(N'Dọn nhà định kỳ', N'Dọn dẹp nhà cửa theo lịch trình cố định hàng tuần hoặc hàng tháng'),
(N'Hồ kỳ tại gia', N'Chăm sóc trẻ em trong thời gian hè, dạy bài và tổ chức hoạt động vui chơi'),
(N'Chăm sóc thú cưng', N'Chăm sóc, cho ăn, tắm rửa và dắt dạo thú cưng khi chủ vắng nhà'),

-- Các dịch vụ đặc biệt khác
(N'Dọn dẹp nhà cửa', N'Vệ sinh tổng thể ngôi nhà, từ phòng khách đến phòng ngủ, nhà bếp, toilet'),
(N'Nấu ăn tại nhà', N'Nấu các bữa ăn hàng ngày cho gia đình theo khẩu vị và yêu cầu dinh dưỡng'),
(N'Đón trẻ', N'Dịch vụ đưa đón trẻ đi học, đi chơi một cách an toàn và đúng giờ'),
(N'Chăm sóc người già', N'Hỗ trợ người cao tuổi trong sinh hoạt, ăn uống, uống thuốc và vận động'),
(N'Tổng vệ sinh', N'Vệ sinh tổng thể toàn bộ ngôi nhà, bao gồm cả những khu vực khó vệ sinh'),

-- Dịch vụ nổi bật
(N'Danh sách người giúp việc uy tín', N'Các nhân viên đã được kiểm chứng, có kinh nghiệm và đánh giá cao'),
(N'Người giúp việc được đánh giá cao', N'Những nhân viên xuất sắc với nhiều đánh giá tích cực từ khách hàng'),

-- Các dịch vụ bổ sung
(N'Giặt ủi', N'Giặt và ủi quần áo, chăn ga gối đệm chuyên nghiệp tại nhà'),
(N'Chăm sóc thú cưng', N'Dịch vụ chăm sóc toàn diện cho các loại thú cưng trong gia đình'),
(N'Sửa chữa điện nước', N'Sửa chữa các thiết bị điện, nước bị hỏng trong gia đình'),
(N'Tư vấn sức khỏe', N'Tư vấn chăm sóc sức khỏe cơ bản cho các thành viên trong gia đình'),
(N'Dạy học tại nhà', N'Dạy kèm các môn học cho trẻ em ngay tại nhà một cách tiện lợi'),


-- Dịch vụ vệ sinh
(N'Dịch vụ vệ sinh nhà cửa', N'Vệ sinh toàn bộ ngôi nhà, bao gồm quét dọn, lau chùi, sắp xếp đồ đạc một cách chuyên nghiệp'),
(N'Vệ sinh văn phòng', N'Dịch vụ vệ sinh cho các văn phòng, công ty, đảm bảo môi trường làm việc sạch sẽ và chuyên nghiệp'),
(N'Vệ sinh sau xây dựng', N'Vệ sinh tổng thể sau khi hoàn thành công trình xây dựng, sửa chữa nhà cửa'),
(N'Vệ sinh kính cửa sổ', N'Chuyên vệ sinh kính cửa sổ, cửa kính, ban công tòa nhà cao tầng'),

-- Dịch vụ chăm sóc
(N'Chăm sóc người già', N'Dịch vụ chăm sóc người cao tuổi tại nhà, hỗ trợ sinh hoạt hàng ngày'),
(N'Chăm sóc trẻ em', N'Dịch vụ trông trẻ, chăm sóc trẻ nhỏ tại nhà khi bố mẹ bận việc'),
(N'Chăm sóc người bệnh', N'Chăm sóc người bệnh tại nhà, hỗ trợ y tế cơ bản và sinh hoạt cá nhân'),

-- Dịch vụ gia đình
(N'Nấu ăn gia đình', N'Dịch vụ nấu ăn tại nhà, chuẩn bị bữa ăn ngon và bổ dưỡng cho gia đình'),
(N'Giặt ủi quần áo', N'Dịch vụ giặt, ủi quần áo chuyên nghiệp tại nhà'),
(N'Mua sắm thực phẩm', N'Dịch vụ mua sắm thực phẩm, đồ gia dụng theo yêu cầu của khách hàng'),

-- Dịch vụ bảo trì
(N'Sửa chữa điện nước', N'Dịch vụ sửa chữa hệ thống điện, nước trong nhà, thay thế thiết bịhỏng hóc'),
(N'Bảo dưỡng điều hòa', N'Vệ sinh, bảo dưỡng máy lạnh, điều hòa không khí định kỳ'),
(N'Sửa chữa đồ gia dụng', N'Sửa chữa các thiết bị gia dụng như tủ lạnh, máy giặt, lò vi sóng'),

-- Dịch vụ đặc biệt
(N'Tổ chức sự kiện tại nhà', N'Hỗ trợ tổ chức tiệc sinh nhật, họp mặt gia đình, sự kiện nhỏ tại nhà'),
(N'Chăm sóc thú cưng', N'Dịch vụ chăm sóc, dắt dạo, tắm rửa cho thú cưng khi chủ vắng nhà'),
(N'Làm vườn', N'Chăm sóc cây cảnh, tưới nước, tỉa cành, thiết kế tiểu cảnh sân vườn'),

-- Dịch vụ theo thời gian
(N'Dịch vụ theo giờ', N'Các công việc gia đình được tính theo giờ, linh hoạt về thời gian'),
(N'Dịch vụ bán thời gian', N'Làm việc bán thời gian, phù hợp với nhu cầu không thường xuyên'),
(N'Dịch vụ toàn thời gian', N'Người giúp việc toàn thời gian, cam kết lâu dài với gia đình'),

-- Dịch vụ khẩn cấp
(N'Dịch vụ khẩn cấp', N'Hỗ trợ khẩn cấp các vấn đề gia đình như rò rỉ nước, mất điện'),
(N'Dịch vụ cuối tuần', N'Các dịch vụ đặc biệt trong ngày cuối tuần và lễ tết'),

(N'Dịch vụ cao cấp', N'Các dịch vụ cao cấp với tiêu chuẩn 5 sao, phục vụ khách hàng VIP'),
(N'Dịch vụ sinh viên', N'Gói dịch vụ giá rẻ dành cho sinh viên và người thu nhập thấp'),
(N'Dịch vụ doanh nghiệp', N'Gói dịch vụ cho các doanh nghiệp, công ty có nhu cầu ổn định'),
(N'Dịch vụ lễ tết', N'Các dịch vụ đặc biệt trong dịp lễ, tết, cần chuẩn bị kỹ lưỡng'),
(N'Dịch vụ quận trung tâm', N'Dịch vụ tại các quận trung tâm thành phố với giá cao hơn'),
(N'Dịch vụ ngoại thành', N'Dịch vụ tại các khu vực ngoại thành với mức giá phù hợp');


